FUNCTION Cost_Complexity_Pruning(tree, training_data, validation_data):
 // Step 1: Grow full tree T_max on training data
 T ← Grow_Full_Tree(training_data)

 // Step 2: Find sequence of subtrees T₁, T₂, ..., T_k
 trees_list ← []
 WHILE T is not root:
 // Find non-leaf node t that minimizes |t| / (R(t) - R(T_t))
 // where R(t) is misclassification rate of node t
 // and R(T_t) is total misclassification rate of subtree rooted at t
 alpha ← min_{(t is non-leaf)} (R(t) - R(T_t)) / (|T_t| - 1)

 // Prune subtree at node t with minimum α
 pruned_tree ← Prune(T, t)
 trees_list.append(pruned_tree)
 T ← pruned_tree

 // Step 3: Select best tree using validation data
 best_tree ← Tree with lowest validation error in trees_list

 RETURN best_tree

FUNCTION R(node):
 // Return misclassification rate at this node
 RETURN 1 - (majority_class_count / total_samples)
